// ============================================
// BUILD PLACID PAYLOAD — SofIA Content Generator
// ============================================

const TEMPLATE_UUIDS = {
  'carousel-slide':   'gq06s1szmh7w0',
  'linkedin-banner':  'qj1ldvpoy3fos',
  'ig-carrusel':      'lf7cxdnzrziuh',
  'comparativa':      'aagzm0th6ub1a',
  'testimonial':      'lw7e1bby8zz0x'
};

const PLACID_TOKEN = 'placid-tjyfszkjr9kqyfct-ybqrbhowrx2ct9tx';

const record = $input.first().json;
const fields = record.fields || record; // Airtable v2 wraps in .fields

const template = fields.template || 'carousel-slide';
const template_uuid = TEMPLATE_UUIDS[template] || TEMPLATE_UUIDS['carousel-slide'];

const slideTotal = fields.slide_total || 1;
const slideNum   = fields.slide_num   || 1;

// Build layers based on template type
let layers = {};

if (template === 'carousel-slide') {
  layers = {
    title:            { text: fields.title || '' },
    subtitle:         { text: fields.subtitle || '' },
    slide_number:     { text: String(slideNum).padStart(2,'0') },
    highlight_number: { text: fields.stat_number || '' }
  };
}
else if (template === 'linkedin-banner') {
  layers = {
    stat_number: { text: fields.stat_number || '' },
    stat_label:  { text: fields.stat_label  || '' },
    title:       { text: fields.title       || '' }
  };
}
else if (template === 'ig-carrusel') {
  layers = {
    title:        { text: fields.title    || '' },
    body:         { text: fields.body     || '' },
    slide_number: { text: slideNum + ' / ' + slideTotal },
    cta:          { text: slideNum === slideTotal ? (fields.cta || 'Escríbenos →') : '' }
  };
}
else if (template === 'comparativa') {
  layers = {
    title:     { text: fields.title    || '' },
    subtitle:  { text: fields.subtitle || '' }
  };
}
else if (template === 'testimonial') {
  layers = {
    quote:  { text: fields.body   || '' },
    name:   { text: fields.title  || '' },
    role:   { text: fields.subtitle || '' }
  };
}

return [{
  json: {
    record_id:     record.id,
    template_uuid,
    template,
    placid_layers: layers,
    placid_token:  PLACID_TOKEN,
    fields
  }
}];

const response = $input.first().json;
const prev     = $node['Build Placid Payload'].json;

return [{
  json: {
    ...prev,
    placid_image_id:  response.id,
    placid_image_url: response.image_url || null,
    placid_status:    response.status || 'queued'
  }
}];

const status_res = $input.first().json;
const prev       = $node['Extraer ID Imagen'].json;

const image_url = status_res.image_url || status_res.url || null;
const status    = status_res.status || 'queued';

return [{
  json: {
    ...prev,
    image_url,
    placid_status: status,
    ready: (status === 'finished' || status === 'completed' || !!image_url)
  }
}];

// Count generated items
const items = $input.all();
return [{ json: { generated_count: items.length } }];
